import json
import re

# Access the stored result
result_key = 'var_functions.query_db:0'
transcript_data = locals().get(result_key, [])

if not transcript_data:
    # It's a file path
    try:
        with open(result_key, 'r') as f:
            transcript_data = json.load(f)
    except:
        transcript_data = []

if transcript_data and len(transcript_data) > 0:
    transcript = transcript_data[0]['Body__c']

    # Check Authority
    authority_confirmed = True
    authority_indicators = [
        "don't have the final say",
        "need to consult",
        "present it to your team"
    ]

    for indicator in authority_indicators:
        if indicator in transcript:
            authority_confirmed = False
            break

    # Check Need
    need_established = False
    need_indicators = [
        "interested in",
        "enhance our simulation capabilities",
        "seems like a great fit"
    ]

    for indicator in need_indicators:
        if indicator in transcript:
            need_established = True
            break

    # Check Budget
    budget_sufficient = False
    if "fits really well" in transcript and "$2,000" in transcript:
        budget_sufficient = True

    # Check Timeline
    timeline_acceptable = False
    if "installations within a day" in transcript:
        timeline_acceptable = True

    # Determine failing factors
    failing_factors = []
    if not budget_sufficient:
        failing_factors.append('Budget')
    if not authority_confirmed:
        failing_factors.append('Authority')
    if not need_established:
        failing_factors.append('Need')
    if not timeline_acceptable:
        failing_factors.append('Timeline')
else:
    failing_factors = []

result = {'failing_factors': failing_factors, 'qualified': len(failing_factors) == 0}
print('__RESULT__:')
print(json.dumps(result))

